SELECT COUNT(1) AS totalCount FROM ( SELECT A.NIP_PRIVATE_REQ_MST_SEQ , A.SIP_PRIVATE_REQ_MST_SEQ_CD , A.SREQUEST_TYPE_CD , A.SREQUEST_TYPE_NM , A.SREQUEST_STAT_CD , (CASE WHEN A.SREQUEST_STAT_CD = 'REQ0001' THEN '접수' WHEN A.SREQUEST_STAT_CD = 'REQ0002' THEN '승인' WHEN A.SREQUEST_STAT_CD = 'REQ0003' THEN '반려' END) AS SREQUEST_STAT_NM , A.SSVC_LINE_TYPE_CD , B.SSVC_LINE_TYPE_NM , A.NLVL_MST_SEQ , C.SSVC_GROUP_CD -- 본부/국사_CD , D.SLVL_NM AS SSVC_GROUP_NM , C.SSVC_OBJ_CD -- 노드_CD , E.SLVL_NM AS SSVC_OBJ_NM , A.PIP_PREFIX , A.SIP_VERSION_TYPE_CD , F.SIP_VERSION_TYPE_NM , A.SIP_CREATE_TYPE_CD , G.SIP_CREATE_TYPE_NM , A.SIP_BLOCK , A.SIP_CREATE_SEQ_CD , A.NBITMASK , A.SNETMASK , A.SFIRST_ADDR , A.SLAST_ADDR , A.NFIRST_ADDR , A.NLAST_ADDR , A.SFIRST_IP_PREFERRED , A.SLAST_IP_PREFERRED , A.SFIRST_ADDR_BINARY , A.SLAST_ADDR_BINARY , A.NCNT , A.NCLASS_CNT , A.NUSE_IP_CNT , A.NFREE_IP_CNT , A.SCOMMENT , A.NIP_BLOCK_MST_SEQ , A.DREQUEST_DT , A.SREQUEST_ID , A.DAPPROVE_DT , A.SAPPROVE_ID FROM MST.TB_IP_PRIVATE_REQ_MST A , MST.TB_SVC_LINE_TYPE_CD B -- 서비스_망_유형_CD , MST.TB_LVL_MST C -- 계위_MST_수동계위포함 , MST.TB_LVL_CD D -- 국사/조직코드_수동포함 , MST.TB_LVL_CD E -- 국사/조직코드_수동포함 , MST.TB_IP_VERSION_TYPE_CD F -- IP_버전_유형 , MST.TB_IP_CREATE_TYPE_CD G -- IP_생성_유형_CD , MST.TB_USER_BAS H WHERE 1=1 AND B.SSVC_LINE_TYPE_CD(+) = A.SSVC_LINE_TYPE_CD AND C.NLVL_MST_SEQ = A.NLVL_MST_SEQ AND D.SLVL_CD(+) = C.SSVC_GROUP_CD AND E.SLVL_CD(+) = C.SSVC_OBJ_CD AND F.SIP_VERSION_TYPE_CD(+) = A.SIP_VERSION_TYPE_CD AND G.SIP_CREATE_TYPE_CD(+) = A.SIP_CREATE_TYPE_CD AND H.SUSER_ID(+) = A.SREQUEST_ID
AND A.SSVC_LINE_TYPE_CD = #{ssvcLineTypeCd, jdbcType=CHAR}
AND A.NLVL_MST_SEQ IN
#{item.nlvlSeq}
AND A.SIP_VERSION_TYPE_CD = #{sipVersionTypeCd, jdbcType=CHAR}
AND A.SREQUEST_TYPE_CD = #{srequestTypeCd, jdbcType=CHAR}
AND A.SREQUEST_STAT_CD = #{srequestStatCd, jdbcType=CHAR}
AND (( A.NFIRST_ADDR >= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'Y') FROM DUAL) AND A.NLAST_ADDR <= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'N') FROM DUAL) ) OR ( A.NFIRST_ADDR <= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'Y') FROM DUAL) AND A.NLAST_ADDR >= (SELECT BIF.UF_SEARCH_IP_TO_NUMBER(#{searchWrd}, 'N') FROM DUAL) ) )
AND A.DREQUEST_DT BETWEEN #{searchBgnDe, jdbcType=TIMESTAMP} AND #{searchEndDe} || ' 23:59:59'
AND A.SIP_PRIVATE_REQ_MST_SEQ_CD = #{sipPrivateReqMstSeqCd, jdbcType=CHAR}
) A

